import{_ as s,c as t,o as n,aj as e}from"./chunks/framework.VtnL2jmu.js";const h=JSON.parse('{"title":"Java Stream API学习","description":"","frontmatter":{},"headers":[],"relativePath":"Java/Java Stream API学习.md","filePath":"Java/Java Stream API学习.md"}'),o={name:"Java/Java Stream API学习.md"};function r(l,a,i,p,d,c){return n(),t("div",null,[...a[0]||(a[0]=[e(`<h1 id="java-stream-api学习" tabindex="-1">Java Stream API学习 <a class="header-anchor" href="#java-stream-api学习" aria-label="Permalink to “Java Stream API学习”">​</a></h1><blockquote><p>从“保姆式”到“老板式”编程</p></blockquote><h2 id="_1-核心思想-流水线模型" tabindex="-1">1. 核心思想：流水线模型 <a class="header-anchor" href="#_1-核心思想-流水线模型" aria-label="Permalink to “1. 核心思想：流水线模型”">​</a></h2><p>Stream（流）不是一种数据结构，它不存储数据，而是对数据源（如 <code>List</code>、<code>Set</code>）进行<strong>连续处理</strong>的工具。</p><ul><li><strong>数据源</strong>：传送带上的原始零件（<code>List&lt;String&gt;</code>）。</li><li><strong>中间操作</strong>：加工工序（<code>filter</code>、<code>map</code>、<code>distinct</code>）。</li><li><strong>终端操作</strong>：最后打包出货（<code>collect</code>、<code>count</code>、<code>forEach</code>）。</li></ul><hr><h2 id="_2-常用-加工工序-速查表" tabindex="-1">2. 常用“加工工序”速查表 <a class="header-anchor" href="#_2-常用-加工工序-速查表" aria-label="Permalink to “2. 常用“加工工序”速查表”">​</a></h2><table tabindex="0"><thead><tr><th><strong>操作名称</strong></th><th><strong>作用</strong></th><th><strong>逻辑简述</strong></th></tr></thead><tbody><tr><td><strong><code>.filter(p)</code></strong></td><td><strong>过滤</strong></td><td>丢弃不符合条件 <code>p</code> 的元素</td></tr><tr><td><strong><code>.map(f)</code></strong></td><td><strong>映射</strong></td><td>把 A 变成 B（例如 String 转对象）</td></tr><tr><td><strong><code>.distinct()</code></strong></td><td><strong>去重</strong></td><td>基于 <code>equals()</code> 去除重复项</td></tr><tr><td><strong><code>.limit(n)</code></strong></td><td><strong>截断</strong></td><td>只保留前 <code>n</code> 个元素</td></tr><tr><td><strong><code>.sorted()</code></strong></td><td><strong>排序</strong></td><td>对流中元素进行排序</td></tr></tbody></table><hr><h2 id="_3-实战案例-帖子图片更新逻辑" tabindex="-1">3. 实战案例：帖子图片更新逻辑 <a class="header-anchor" href="#_3-实战案例-帖子图片更新逻辑" aria-label="Permalink to “3. 实战案例：帖子图片更新逻辑”">​</a></h2><p>这是我们之前讨论的代码模型，它展示了 Stream 如何优雅地处理<strong>清洗 + 转换</strong>。</p><p>Java</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>List&lt;PostImages&gt; cleanedImages = imagesList.stream()</span></span>
<span class="line"><span>    // 1. 数据清洗：去空、去空格</span></span>
<span class="line"><span>    .filter(url -&gt; url != null &amp;&amp; !url.trim().isEmpty())</span></span>
<span class="line"><span>    .map(String::trim)</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // 2. 业务去重</span></span>
<span class="line"><span>    .distinct()</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // 3. 类型转换：String -&gt; Entity</span></span>
<span class="line"><span>    .map(url -&gt; {</span></span>
<span class="line"><span>        PostImages pi = new PostImages();</span></span>
<span class="line"><span>        pi.setPostId(postId);</span></span>
<span class="line"><span>        pi.setImageUrl(url);</span></span>
<span class="line"><span>        pi.setStatus(1);</span></span>
<span class="line"><span>        return pi;</span></span>
<span class="line"><span>    })</span></span>
<span class="line"><span>    </span></span>
<span class="line"><span>    // 4. 落地存储</span></span>
<span class="line"><span>    .collect(Collectors.toList());</span></span></code></pre></div><hr><h2 id="_4-为什么要用-stream-避坑指南" tabindex="-1">4. 为什么要用 Stream？（避坑指南） <a class="header-anchor" href="#_4-为什么要用-stream-避坑指南" aria-label="Permalink to “4. 为什么要用 Stream？（避坑指南）”">​</a></h2><h3 id="✅-优点" tabindex="-1">✅ 优点 <a class="header-anchor" href="#✅-优点" aria-label="Permalink to “✅ 优点”">​</a></h3><ol><li><strong>代码简洁</strong>：一行流式代码能顶过去 10 行 <code>for</code> + <code>if</code>。</li><li><strong>语义清晰</strong>：看方法名就知道在做什么，不需要人肉跟踪循环变量。</li><li><strong>减少 Bug</strong>：自动处理集合初始化，减少了空指针和索引越界的风险。</li></ol><h3 id="⚠️-注意事项" tabindex="-1">⚠️ 注意事项 <a class="header-anchor" href="#⚠️-注意事项" aria-label="Permalink to “⚠️ 注意事项”">​</a></h3><ol><li><strong>惰性求值</strong>：只有调用了 <code>.collect()</code> 或 <code>.forEach()</code> 这种<strong>终端操作</strong>，前面的过滤和映射才会真正执行！</li><li><strong>不可逆性</strong>：流就像流水，流过去就没了。如果需要多次操作，必须重新调用 <code>.stream()</code>。</li><li><strong>方法引用</strong>：当 Lambda 只是调用现有方法时，用 <code>ClassName::MethodName</code>（如 <code>String::trim</code>）会让代码更专业。</li></ol><hr><h2 id="_5-进阶-快速转-map" tabindex="-1">5. 进阶：快速转 Map <a class="header-anchor" href="#_5-进阶-快速转-map" aria-label="Permalink to “5. 进阶：快速转 Map”">​</a></h2><p>在做业务逻辑比对（如：找出数据库里已有的图片）时非常有用：</p><p>Java</p><div class="language-"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>// 将 List 转为 Map，Key 是 ID，Value 是对象本身</span></span>
<span class="line"><span>Map&lt;Long, PostImages&gt; imageMap = existingImages.stream()</span></span>
<span class="line"><span>    .collect(Collectors.toMap(PostImages::getId, img -&gt; img));</span></span></code></pre></div><hr><blockquote><p><strong>💡 心得</strong>：</p><p>写代码不只是为了让机器运行，更是为了让人阅读。Stream 让代码从“如何做”变成了“做什么”。</p></blockquote>`,26)])])}const m=s(o,[["render",r]]);export{h as __pageData,m as default};
